# app/controllers/configurations_controller.rb
class ConfigurationsController < ApplicationController
  before_action :authenticate_user!
  before_action :validate_file_presence, only: [:import]

  ALLOWED_MAX_FILE_SIZE = 5.megabytes
  ALLOWED_CONTENT_TYPES = %w[application/x-yaml text/yaml text/plain].freeze
  # Add any custom permitted classes your enterprise configs actually need
  PERMITTED_CLASSES = [Date, Time, DateTime, Symbol, Regexp].freeze
  PERMITTED_SYMBOLS = [].freeze

  def new
    # Render upload form
  end

  def import
    unless valid_file_type?
      return render json: { error: "Invalid file type. Only YAML files are accepted." }, status: :unprocessable_entity
    end

    unless valid_file_size?
      return render json: { error: "File too large. Maximum size is #{ALLOWED_MAX_FILE_SIZE / 1.megabyte}MB." }, status: :unprocessable_entity
    end

    raw_content = params[:config_file].read

    # SECURITY: NEVER use YAML.load() with user-supplied input.
    # YAML.load() can deserialize arbitrary Ruby objects, enabling Remote Code Execution.
    # ALWAYS use YAML.safe_load() which only allows basic types by default.
    config_data = parse_yaml_safely(raw_content)

    if config_data.nil?
      return render json: { error: "YAML file is empty or contains no valid data." }, status: :unprocessable_entity
    end

    validation_errors = validate_config_structure(config_data)
    if validation_errors.any?
      return render json: { errors: validation_errors }, status: :unprocessable_entity
    end

    configuration = current_user.configurations.build(
      name: params[:name] || extract_config_name(params[:config_file]),
      data: config_data,
      version: next_version_for(params[:name]),
      uploaded_by: current_user.id,
      source_filename: params[:config_file].original_filename
    )

    if configuration.save
      AuditLog.record(
        user: current_user,
        action: "config_import",
        resource: configuration,
        details: "Imported configuration from #{params[:config_file].original_filename}"
      )

      render json: {
        message: "Configuration imported successfully.",
        configuration: ConfigurationSerializer.new(configuration)
      }, status: :created
    else
      render json: { errors: configuration.errors.full_messages }, status: :unprocessable_entity
    end

  rescue Psych::SyntaxError => e
    render json: { error: "Invalid YAML syntax: #{e.message}" }, status: :unprocessable_entity
  rescue Psych::DisallowedClass => e
    # This is triggered when YAML contains objects not in the permitted list
    # This is the security mechanism working as intended
    Rails.logger.warn(
      "Blocked potentially dangerous YAML upload by user #{current_user.id}: #{e.message}"
    )
    render json: {
      error: "YAML file contains disallowed object types. " \
             "Only plain data structures (strings, numbers, arrays, hashes, dates) are permitted. " \
             "Complex Ruby objects are not allowed for security reasons."
    }, status: :unprocessable_entity
  rescue StandardError => e
    Rails.logger.error("Configuration import failed: #{e.class} - #{e.message}")
    render json: { error: "An unexpected error occurred during import." }, status: :internal_server_error
  end

  def show
    @configuration = current_user.configurations.find(params[:id])
    render json: ConfigurationSerializer.new(@configuration)
  end

  def index
    @configurations = current_user.configurations.order(created_at: :desc).page(params[:page])
    render json: @configurations.map { |c| ConfigurationSerializer.new(c) }
  end

  def export
    @configuration = current_user.configurations.find(params[:id])
    yaml_output = YAML.dump(@configuration.data)

    send_data yaml_output,
              filename: "#{@configuration.name}_v#{@configuration.version}.yml",
              type: "application/x-yaml",
              disposition: "attachment"
  end

  private

  def parse_yaml_safely(raw_content)
    # YAML.safe_load is the secure alternative:
    # - Only permits basic Ruby types by default (String, Integer, Float, NilClass,
    #   TrueClass, FalseClass, Array, Hash)
    # - Additional classes must be explicitly permitted
    # - Cannot instantiate arbitrary Ruby objects
    # - Prevents deserialization attacks entirely
    YAML.safe_load(
      raw_content,
      permitted_classes: PERMITTED_CLASSES,
      permitted_symbols: PERMITTED_SYMBOLS,
      aliases: true  # Allow YAML anchors/aliases if needed for DRY configs
    )
  end

  def validate_file_presence
    unless params[:config_file].present?
      render json: { error: "No file provided. Please upload a YAML configuration file." }, status: :unprocessable_entity
    end
  end

  def valid_file_type?
    file = params[:config_file]
    return false unless file.respond_to?(:content_type) && file.respond_to?(:original_filename)

    ALLOWED_CONTENT_TYPES.include?(file.content_type) ||
      file.original_filename&.match?(/\.(ya?ml)\z/i)
  end

  def valid_file_size?
    params[:config_file].size <= ALLOWED_MAX_FILE_SIZE
  end

  def validate_config_structure(config_data)
    errors = []

    unless config_data.is_a?(Hash)
      errors << "Configuration root must be a YAML mapping (hash), got #{config_data.class.name}."
      return errors
    end

    # Enterprise-specific validations
    errors << "Configuration must include a 'version' key." unless config_data.key?("version")
    errors << "Configuration must include an 'environment' key." unless config_data.key?("environment")

    if config_data.key?("environment")
      allowed_envs = %w[development staging production]
      unless allowed_envs.include?(config_data["environment"])
        errors << "Environment must be one of: #{allowed_envs.join(', ')}."
      end
    end

    # Check for excessively nested structures (potential DoS)
    if max_depth(config_data) > 20
      errors << "Configuration nesting depth exceeds maximum allowed (20 levels)."
    end

    errors
  end

  def max_depth(obj, current_depth = 0)
    case obj
    when Hash
      return current_depth if obj.empty?
      obj.values.map { |v| max_depth(v, current_depth + 1) }.max
    when Array
      return current_depth if obj.empty?
      obj.map { |v| max_depth(v, current_depth + 1) }.max
    else
      current_depth
    end
  end

  def extract_config_name(file)
    File.basename(file.original_filename, File.extname(file.original_filename))
        .gsub(/[^a-zA-Z0-9_\-]/, "_")
        .truncate(100)
  end

  def next_version_for(name)
    latest = current_user.configurations.where(name: name).maximum(:version)
    (latest || 0) + 1
  end
end